import pytest
from datetime import datetime, timedelta, timezone

def test_schedule_review_exactly_7_days_out_accepted(
    manager_api_client,
    valid_reviewee_id,
    totp_token,
):
    # Add 30 extra seconds to avoid sub-second clock skew on the boundary
    scheduled_at = (
        datetime.now(timezone.utc) + timedelta(days=7, seconds=30)
    ).isoformat()
    payload = {
        "reviewee_id": valid_reviewee_id,
        "scheduled_at": scheduled_at,
        "two_fa_token": totp_token,
    }
    response = manager_api_client.post("/performance-reviews/schedule", json=payload)
    assert response.status_code == 201, (
        f"Expected 201 at 7-day boundary, got {response.status_code}: {response.text}"
    )
